/*
Theme Name:     Daze
Theme URI:      https://daze-demo.heartenmade.com
Template:       kadence
Author:         Hearten Made // Carissa Allen
Author URI:     https://heartenmade.com
Description:    A feminine, responsive WordPress theme built on Kadence.
Version:        1_0_0
License:        GNU General Public License v3.0 (or later)
License URI:    https://www.gnu.org/licenses/gpl-3.0.html
*/

@font-face {
    font-family: 'Haigrast';
    src: url('lib/fonts/Haigrast-Regular.woff2') format('woff2');
    font-style: normal;
    font-weight: normal;
    text-rendering: optimizeLegibility;
    font-display: swap;
}

/* Flodesk */

.ff__form {
	max-width: 100%;
}

.ff__cell,
.ff__button {
	margin: 10px 0 0 0;
}

.ff__control,
.ff__root,
.ff__container {
	background: transparent !important;
	width: 100%;
}

.ff__button {
	margin: 10px 0 0 0;
	width: 100%;
}

.ff__success {
	display: none;
}

.fd-has-success .ff__success {
	display: block;
	margin-top: 20px;
   text-align: center;
}

.ff__success>*:last-child {
	margin-bottom: 0;
}

.ff__error {
	margin: 10px 0 0 0;
	display: none;
}

.fd-has-error .ff__error {
	display: block;
}

.ff__error>*:last-child {
	margin-bottom: 0;
}


/* General
---------------------------------------- */

body {
	-webkit-font-smoothing: subpixel-antialiased;
	overflow-x: hidden;
}

h1,
h2,
h3,
h4,
h5,
h6 {
	-webkit-font-smoothing: antialiased;
}

a {
	transition: all .2s ease-in-out !important;
	text-underline-position: under;
}

::selection {
    background: var(--global-palette3);
    color: var(--global-palette9);
}

input,
select,
textarea {
	border-radius: 0 !important;
}

.header-navigation[class*="header-navigation-style-underline"] .header-menu-container>ul>li>a:after {
	height: 1px;
}

select,
textarea,
.comment-form input:placeholder-shown+label,
.comment-form textarea:placeholder-shown+label,
.comment-form .comment-input-wrap p label,
.comment-form p.comment-form-float-label label,
.comment-form input:placeholder-shown+label,
.comment-form textarea:placeholder-shown+label,
textarea::-webkit-input-placeholder,
input[type="text"],
input[type="email"],
input[type="url"],
input[type="password"],
input[type="search"],
input[type="number"],
input[type="tel"],
input[type="range"],
input[type="date"],
input[type="month"],
input[type="week"],
input[type="time"],
input[type="datetime"],
input[type="datetime-local"],
input[type="color"],
input[type="text"]::-webkit-input-placeholder,
input[type="email"]::-webkit-input-placeholder,
input[type="url"]::-webkit-input-placeholder,
input[type="password"]::-webkit-input-placeholder,
input[type="search"]::-webkit-input-placeholder,
input[type="number"]::-webkit-input-placeholder,
input[type="tel"]::-webkit-input-placeholder,
input[type="range"]::-webkit-input-placeholder,
input[type="date"]::-webkit-input-placeholder,
input[type="month"]::-webkit-input-placeholder,
input[type="week"]::-webkit-input-placeholder,
input[type="time"]::-webkit-input-placeholder,
input[type="datetime"]::-webkit-input-placeholder,
input[type="datetime-local"]::-webkit-input-placeholder,
input[type="color"]::-webkit-input-placeholder,
.enews input::-webkit-input-placeholder {
	color: var(--global-palette3) !important;
	border-color: var(--global-palette3) !important;
	font-size: 90%;
}

input[type="text"]::-webkit-input-placeholder,
input[type="email"]::-webkit-input-placeholder,
input[type="url"]::-webkit-input-placeholder,
input[type="password"]::-webkit-input-placeholder,
input[type="search"]::-webkit-input-placeholder,
input[type="number"]::-webkit-input-placeholder,
input[type="tel"]::-webkit-input-placeholder,
input[type="range"]::-webkit-input-placeholder,
input[type="date"]::-webkit-input-placeholder,
input[type="month"]::-webkit-input-placeholder,
input[type="week"]::-webkit-input-placeholder,
input[type="time"]::-webkit-input-placeholder,
input[type="datetime"]::-webkit-input-placeholder,
input[type="datetime-local"]::-webkit-input-placeholder,
input[type="color"]::-webkit-input-placeholder,
.enews input::-webkit-input-placeholder {
	letter-spacing: 2px;
	font-size: 11px;
	text-transform: uppercase;
	font-weight: inherit;
}

.drawer-content input[type="search"]::-webkit-input-placeholder {
	font-size: inherit;
}

textarea,
tr,
td,
th,
.woocommerce div.product .woocommerce-tabs {
	border-color: var(--global-palette3) !important;
}

blockquote,
.wp-block-quote.is-large p,
.wp-block-quote.is-style-large p,
.wp-block-quote.is-style-default {
	font-family: var(--global-heading-font-family) !important;
	font-style: normal;
	padding: 20px 10px;
}

.wp-block-quote.is-large p,
.wp-block-quote.is-style-large p {
	font-size: 1.8em;
}

button[type="submit"] {
	border-color: var(--global-palette3);
	color: var(--global-palette-btn);
	background-color: var(--global-palette-btn-bg);
	font-family: inherit;
}

button[type="submit"]:hover {
	border-color: var(--global-palette-btn-border-hover);
	color: var(--global-palette-btn-hover);
	background-color: var(--global-palette-btn-bg-hover);
}

/* Kadence Form
---------------------------------------- */

.kadence-form-_f4af2b-56 .kb-form .kadence-blocks-form-field .kb-forms-submit {
	font-weight: inherit;
}

/* Search Results
---------------------------------------- */

.search-archive-title h1 {
    padding-bottom: .35em;
}

/* Search
---------------------------------------- */

#search-drawer .drawer-inner .drawer-content form input.search-field,
#search-drawer .drawer-inner .drawer-content form input.search-field:focus {
    box-shadow: none !important;
}

#search-drawer .drawer-inner input.search-field {
    padding: 1.5em 80px 1.5em 1.5em !important;
}

.search-results .content-container .entry-content-wrap {
    margin-top: 15px;
}

.search-form .kadence-search-icon-wrap {
	color: var(--global-palette3) !important;
}

/* Header
---------------------------------------- */

.site-top-header-wrap {
	background: var(--global-palette9);
}

/* Entries
---------------------------------------- */

.entry-tags a.tag-link {
	border: 0 !important;
	color: solid var(--global-palette3) !important;
}

.entry-tags a.tag-link:hover {
	color: var(--global-palette-btn) !important;
	border-radius: 0;
}

.entry-header .category-links a {
    font-weight: normal !important;
}

.content-style-unboxed .kadence-thumbnail-position-behind:after {
	background: none !important;
}

.content-style-unboxed .kadence-thumbnail-position-behind {
    margin-bottom: 3em;
}

.post-navigation {
    margin: var(--global-xl-spacing) auto !important;
}

/* Posts Block */

.wp-block-kadence-posts.item-image-style-beside article.loop-entry.has-post-thumbnail {
    grid-gap: 2rem;
}

.transparent-bg .content-bg,
.kb-posts-style-unboxed .content-bg {
    background: transparent !important;
}

/* related */

.tns-outer .tns-controls button[data-controls="prev"]:before,
.tns-outer .tns-controls button[data-controls="next"]:before {
	height: 15px !important;
	width: 15px !important;
}

/* Entry Nav
---------------------------------------- */
.pagination .page-numbers {
	border-radius: 0 !important;
	font-size: .85em;
}

.pagination .kadence-svg-iconset svg {
    height: .9em;
    width: .9em;
}

/* Comments
---------------------------------------- */

.comments-area {
	background: #fff;
	padding: 30px;
	margin-bottom: 2em;
}

p.form-submit {
	margin-bottom: 0 !important;
}

.comment-reply-link {
	color: var(--global-palette3) !important;
	border-color: var(--global-palette3) !important;
	opacity: .75;
}

.comment-reply-link:hover {
	opacity: 1;
}

.comment-respond a#cancel-comment-reply-link {
    margin-left: 20px;
    font-size: .75em;
    text-decoration: underline;
}

#respond + .comments-title {
    margin-top: 2em !important;
}

.comment-navigation .nav-previous:after,
.post-navigation .nav-previous:after {
	background: var(--global-palette3) !important;
}

.comment-body {
	border-bottom: 1px solid var(--global-palette4) !important;
}

.comment-author .fn a {
    text-transform: uppercase;
    letter-spacing: 1.5px;
    font-size: .8em;
}

/* Sidebars
---------------------------------------- */

.widget select {
	width: 100%;
}

.primary-sidebar {
	text-align: center;
}

.block-sidebar li.widget {
    list-style-type: none;
}

.block-sidebar .widget {
    padding: 12px 0;
    text-align: center;
}

.block-sidebar h2.widgettitle {
    font-size: 22px;
    font-weight: initial;
    text-align: center;
}

.block-sidebar .widget ul {
    padding: 0;
}

.block-sidebar .widget ul li {
    padding: 3px 0;
}

.primary-sidebar .widget_media_image img,
.block-sidebar .widget_media_image img {
    text-align: center;
    margin: auto;
}

/* Genesis eNews Extended
--------------------------------------------- */ 

.enews input,
.enews input:focus,
.site-footer-wrap .enews input,
.site-footer-wrap .enews input:focus,
.primary-sidebar .enews input,
.primary-sidebar .enews input:focus,
.block-sidebar .enews input,
.block-sidebar .enews input:focus {
	border: 1px solid var(--global-palette3);
	width: 100%;
	font-size: 88%;
}

.enews input[type="submit"],
.site-footer-wrap .enews input[type="submit"],
.primary-sidebar .enews input[type="submit"],
.block-sidebar .enews input[type="submit"] {
	margin: 0;
	border: 0;
	width: 100%;
}

.primary-sidebar .enews,
.block-sidebar .enews {
	border: 1px solid var(--global-palette3);
	padding: 30px;
	text-align: center;
}

.enews {
	padding: 10px;
	text-align: center;
}

.enews input[type="text"],
.enews input[type="email"],
.enews input[type="text"]:focus,
.enews input[type="email"]:focus {
	background: transparent;
	border-left: 0;
	border-right: 0;
	border-top: 0;
	padding: 0 0 2px 0;
}

.enews input[type="text"],
.enews input[type="email"] {
	margin-bottom: 15px;
}

.enews input {
	margin-bottom: 10px;
	color: var(--global-palette3);
}

.enews form + p {
	margin-top: 20px;
}

.block-newsletter li {
    list-style-type: none;
}

.block-newsletter .enews {
	padding: 10px 0;
}

/* Blocks
---------------------------------------- */

blockquote,
q {
    quotes: '“' '”';
}

blockquote {
    padding-left: 0;
    border-left: 0px;
}

.entry-content blockquote {
    margin: var(--global-md-spacing) 0 0;
}

.entry-content {
    word-break: initial !important;
}

blockquote cite,
blockquote .wp-block-pullquote__citation {
    color: var(--global-palette3);
    font-size: 13px;
    margin-top: 1em;
    position: relative;
    font-style: normal;
    display: block;
}

blockquote cite::before {
	content:"";
	display: inline-block;
	vertical-align: middle;
	margin-right: 5px;
	width: 35px;
	height: 1px;
	background: var(--global-palette3);
}

.wp-block-kadence-spacer.aligncenter { 
	width: 100%;
}

.blocks-gallery-caption figcaption, .wp-block-embed figcaption,
.wp-block-image figcaption,
.wp-block-table figcaption,
.wp-block-audio figcaption,
.wp-block-video figcaption {
	color: var(--global-palette3) !important;
}

.kt-svg-icons + p {
    margin-top: 10px !important;
}

.kt-blocks-carousel .slick-dots li button:before {
	width: 6px !important;
	height: 6px !important;
}

.kt-blocks-carousel .kt-carousel-arrowstyle-outlinewhite .slick-prev,
.kt-blocks-carousel .kt-carousel-arrowstyle-outlinewhite .slick-next,
.kt-blocks-carousel .kt-carousel-arrowstyle-outlineblack .slick-prev,
.kt-blocks-carousel .kt-carousel-arrowstyle-outlineblack .slick-next {
	border: 1px solid !important;
}

.kt-blocks-carousel .slick-prev:before,
.kt-blocks-carousel .slick-next:before {
	border-width: 1px 1px 0 0 !important;
	width: 15px !important;
	height: 15px !important;
}

/* Custom Styles
---------------------------------------- */

.vertical-line .kt-divider {
    width: 1px !important;
}

.justify {
	text-align: justify;
	text-align-last: center;
}

.image-block-border img {
	border: 10px solid #fff;
}

.image-block-border-large img {
	border: 30px solid #fff;
}

.script {
    font-family: 'printedmoments' !important;
    -webkit-font-smoothing: subpixel-antialiased;
    font-size: 42px;
    word-spacing: -4px;
    line-height: 1.75;
		position: relative;
    z-index: 99;
}

.inside-border img {
    outline: 1px solid white;
    outline-offset: -25px;
}

/* Footer */

.footer-widgets .collapse-sub-navigation ul.menu li a {
	border-bottom: 0 !important;
}

/* WooCommerce
---------------------------------------- */

.quantity.spinners-added input.minus, .quantity.spinners-added input.plus {
    border: 0 !important;
}

.woocommerce .return-to-shop a.button,
a.button {
    background: var(--global-palette-btn-bg);
	color: var(--global-palette-btn);
}

.woocommerce-account .account-navigation-wrap .kadence-account-avatar .kadence-customer-name {
	font-size: 22px;
}

.quantity,
.quantity.spinners-added,
.select2-container--default .select2-selection--single .select2-selection__rendered,
.woocommerce div.product .woocommerce-tabs ul.tabs li {
	border-color: var(--global-palette3) !important;
	color: var(--global-palette3) !important;
}

.woocommerce div.product .woocommerce-tabs ul.tabs::before {
	border-color: var(--global-palette3) !important;
}

.woocommerce div.product .woocommerce-tabs ul.tabs li.active a {
	color: var(--global-palette3) !important;
}

.woocommerce div.product .woocommerce-tabs ul.tabs li a {
	color: var(--global-palette4) !important;
}

.woocommerce div.product .button.single_add_to_cart_button {
	line-height: 1 !important;
}

.kadence-product-toggle-container .kadence-toggle-shop-layout {
	border: 0 !important;
}

.quantity.spinners-added input.minus,
.quantity.spinners-added input.plus,
.woocommerce-cart table.cart .product-name a,
.woocommerce-checkout table.cart .product-name a,
#add_payment_method table.cart .product-name a,
.woocommerce form label {
	color: var(--global-palette3) !important;
	text-decoration: none;
}

#wrapper .wc-block-grid .wc-block-grid__products .product-loop-boxed .entry-content-wrap, #wrapper .wc-block-grid .wc-block-grid__products .woo-archive-action-on-hover .entry-content-wrap,
.woocommerce ul.products li.product .entry-content-wrap, .quantity {
	border-radius: 0 !important;
}

.wc-block-grid__products .wc-block-grid__product .wc-block-grid__product-onsale,
.woocommerce span.onsale {
	border-radius: 0 !important;
	letter-spacing: 1px;
	padding: .7em 1em !important;
	font-weight: normal !important;
}

.woocommerce-cart table.cart .coupon .button:not(:hover),
.woocommerce-checkout table.cart .coupon .button:not(:hover),
#add_payment_method table.cart .coupon .button:not(:hover),
.woocommerce-cart table.cart td.actions .button:disabled,
.woocommerce-checkout table.cart td.actions .button:disabled,
#add_payment_method table.cart td.actions .button:disabled {
    background: var(--global-palette-btn-bg) !important;
	color: var(--global-palette-btn) !important;
}

.woocommerce a.button.alt, .woocommerce button.button.alt, .woocommerce input.button.alt, .woocommerce #respond input#submit.alt {
    -webkit-font-smoothing: subpixel-antialiased !important;
}

/* Media Queries
---------------------------------------- */

@media (max-width: 1024px) and (min-width: 768px) {
	.kt-tab-layout-first-row.kt-gutter-none>.wp-block-kadence-column.inner-column-2 {
		margin-right: 1px;
	}

	.kt-tab-layout-first-row.kt-gutter-none>.wp-block-kadence-column.inner-column-3 {
		margin-left: -1px;
	}
}

@media all and (max-width: 640px) {
	#sb_instagram.sbi_col_3 #sbi_images .sbi_item,
	#sb_instagram.sbi_col_4 #sbi_images .sbi_item,
	#sb_instagram.sbi_col_5 #sbi_images .sbi_item,
	#sb_instagram.sbi_col_6 #sbi_images .sbi_item {
    	width: 50% !important;
	}

	#sb_instagram.sbi_col_7 #sbi_images .sbi_item,
	#sb_instagram.sbi_col_8 #sbi_images .sbi_item,
	#sb_instagram.sbi_col_9 #sbi_images .sbi_item,
	#sb_instagram.sbi_col_10 #sbi_images .sbi_item {
		width: 25% !important;
	}
}

@media all and (max-width: 480px) {
	#sb_instagram.sbi_col_3 #sbi_images .sbi_item,
	#sb_instagram.sbi_col_4 #sbi_images .sbi_item,
	#sb_instagram.sbi_col_5 #sbi_images .sbi_item,
	#sb_instagram.sbi_col_6 #sbi_images .sbi_item,
	#sb_instagram.sbi_col_7 #sbi_images .sbi_item,
	#sb_instagram.sbi_col_8 #sbi_images .sbi_item,
	#sb_instagram.sbi_col_9 #sbi_images .sbi_item,
	#sb_instagram.sbi_col_10 #sbi_images .sbi_item {
		width: 50% !important;
	}
}
